async function to(promise) {
  try {
    const result = await promise;
    return [null, result];
  } catch (error) {
    return [error];
  }
}

async function fetchData() {
  const [error, response] = await to(fetch('https://api.example.com/data'));
  if (error) {
    console.error('Fetch failed:', error);
