class DatabaseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'DatabaseError';
  }
}

function fetchUser(id: number) {
  if (id <= 0) {
    throw new DatabaseError('Invalid user ID');
  }
  // Simulate database fetch
  return { id, name: 'Alice' };
