    }
    throw error;  // Unknown error
  }
}

interface AppError {
  code: string;
  message: string;
  details?: any;
}

function createError(code: string, message: string, details?: any): AppError {
  return { code, message, details };
}

function validateInput(input: string): AppError | null {
  if (!input) {
    return createError('VALIDATION_ERROR', 'Input cannot be empty');
  }
  return null;
}

function process(input: string): string | AppError {
  const error = validateInput(input);
  if (error) return error;
  return `Processed: ${input}`;
}

const result = process('');
if ('code' in result) {
  console.error(`Error [${result.code}]: ${result.message}`);
} else {
  console.log(result);
}

type Result<T, E> = { ok: true; value: T } | { ok: false; error: E };

function parseNumber(input: string): Result<number, string> {
  const parsed = Number(input);
  if (isNaN(parsed)) {
    return { ok: false, error: 'Invalid number format' };
  }
  return { ok: true, value: parsed };
}

function double(input: string): Result<number, string> {
  const numResult = parseNumber(input);
  if (!numResult.ok) {
    return numResult;  // Propagate error
  }
  return { ok: true, value: numResult.value * 2 };
}

